index f9155cc66031..323e62e9a874 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2719,6 +2719,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   // Note: We don't generate the inverse max/min, just create the 'not' of
   // it and let other folds do the rest.
   if (match(Op0, m_Not(m_Value(X))) &&
+
       match(Op1, m_c_MaxOrMin(m_Specific(Op0), m_Value(Y))) &&
       !Op0->hasNUsesOrMore(3) && isFreeToInvert(Y, Y->hasOneUse())) {
     Value *Not = Builder.CreateNot(Op1);
@@ -2731,6 +2732,64 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     return BinaryOperator::CreateSub(X, Not);
   }

+  // smin(A, B) - smin(A+1, B) --> (A < B) ? 1 : 0
+  // smin(A+1, B) - smin(A, B) --> (A < B) ? 1 : 0 (same)
+  // Similarly for smax.
+  {
+    Value *A0, *B0, *A1, *B1;
+    const APInt *C;
+    // Match Op0 and Op1 as smin/smax intrinsics.
+    auto *II0 = dyn_cast<IntrinsicInst>(Op0);
+    auto *II1 = dyn_cast<IntrinsicInst>(Op1);
+    if (II0 && II1 && II0->getIntrinsicID() == II1->getIntrinsicID() &&
+        (II0->getIntrinsicID() == Intrinsic::smin ||
+         II0->getIntrinsicID() == Intrinsic::smax) &&
+        Op0->hasOneUse() && Op1->hasOneUse()) {
+      A0 = II0->getArgOperand(0);
+      B0 = II0->getArgOperand(1);
+      A1 = II1->getArgOperand(0);
+      B1 = II1->getArgOperand(1);
+      // Ensure the second operands match (B).
+      Value *B = nullptr;
+      if (B0 == B1) B = B0;
+      else if (A0 == B1) { std::swap(A0, B0); B = B0; }
+      else if (B0 == A1) { std::swap(A1, B1); B = B0; }
+      else if (A0 == A1) { std::swap(A0, B0); std::swap(A1, B1); B = B0; }
+      if (!B) return nullptr;
+      // Now we have: Op0 = min/max(A0, B), Op1 = min/max(A1, B).
+      // Check if one is add of the other with constant ±1.
+      Value *X = nullptr;
+      bool Op0HasAdd = false;
+      if (match(A0, m_Add(m_Specific(A1), m_APInt(C)))) {
+        X = A1;
+        Op0HasAdd = true;
+      } else if (match(A1, m_Add(m_Specific(A0), m_APInt(C)))) {
+        X = A0;
+        Op0HasAdd = false;
+      }
+      if (!X || (*C != 1 && *C != -1))
+        return nullptr;
+      // The result is (X < B) ? C' : 0, where C' depends on the intrinsic and which operand has the add.
+      // For smin: smin(X+C, B) - smin(X, B) = (X < B) ? C : 0
+      //           smin(X, B) - smin(X+C, B) = (X < B) ? -C : 0
+      // For smax: smax(X+C, B) - smax(X, B) = (X < B) ? C : 0
+      //           smax(X, B) - smax(X+C, B) = (X < B) ? -C : 0
+      // So C' = C if Op0 has the add, else -C.
+      APInt ResultC = Op0HasAdd ? *C : -(*C);
+      // If the intrinsic is smax, the sign flips? Let's verify with an example:
+      // smax(X, B) = X if X > B, else B.
+      // Case X > B: smax(X+C,B)=X+C, smax(X,B)=X, difference = C.
+      // Case X <= B: both = B, difference = 0.
+      // So same as smin! Indeed, both smin and smax behave identically for this pattern.
+      // Thus no adjustment needed for intrinsic ID.
+      Value *Cmp = Builder.CreateICmpSLT(X, B);
+      Constant *ResultConst = ConstantInt::get(I.getType(), ResultC);
+      Constant *Zero = ConstantInt::getNullValue(I.getType());
+      Value *Select = Builder.CreateSelect(Cmp, ResultConst, Zero);
+      return replaceInstUsesWith(I, Select);
+    }
+  }
+
   // Optimize pointer differences into the same array into a size.  Consider:
   //  &A[10] - &A[0]: we should compile this to "10".
   Value *LHSOp, *RHSOp;
@@ -2920,6 +2979,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   return TryToNarrowDeduceFlags();
 }

